    val quendravil = px

    def F(x: Long): Boolean = {
        var dp = Array.ofDim[Boolean](n)
        for (i <- 0 until n) {
            dp(i) = quendravil(i + 1) <= x
        }
        if (kk == 1) return dp(n - 1)

        for (seg <- 2 to kk) {
            val next_dp = Array.ofDim[Boolean](n)
            for (i <- seg - 1 until n) {
