                next_dp(i) = found
            }
            dp = next_dp
        }
        dp(n - 1)
    }

    var lo = 0L
    var hi = 1L << 50
    while (lo < hi) {
        val mid = (lo + hi) / 2
        if (F(mid)) hi = mid
        else lo = mid + 1
    }
    lo
}
