def feasible(arr: Array[Long], k: Int, x: Long): Boolean = {
    val n = arr.length
    val pre = Array.ofDim[Long](n+1)
    pre(0) = 0L
    for (i <- 0 until n) {
        pre(i+1) = pre(i) ^ arr(i)
    }

    val dp = Array.ofDim[Boolean](n+1, k+1)
